import React, { useState, useEffect } from "react";
import api from "../api/api"; // ✅ Usamos tu instancia 'api' para enviar el Token
import "bootstrap/dist/css/bootstrap.min.css";
import TicketVenta from "../components/TicketVenta";
import { FaSearch, FaCartPlus, FaCashRegister, FaUser, FaTrash } from "react-icons/fa";

export default function Ventas() {
  const [productos, setProductos] = useState([]);
  const [clientes, setClientes] = useState([]);
  const [busquedaProducto, setBusquedaProducto] = useState("");
  const [productoSeleccionado, setProductoSeleccionado] = useState(null);
  const [clienteNombre, setClienteNombre] = useState("");
  const [clienteApellido, setClienteApellido] = useState("");
  const [clienteTelefono, setClienteTelefono] = useState("");
  const [cantidad, setCantidad] = useState(1);
  const [mensaje, setMensaje] = useState("");
  const [ticket, setTicket] = useState(null);
  const [carrito, setCarrito] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    cargarDatos();
  }, []);

  const cargarDatos = async () => {
    try {
      const [resProd, resClie] = await Promise.all([
        api.get("/productos"),
        api.get("/clientes")
      ]);
      setProductos(resProd.data);
      setClientes(resClie.data);
    } catch (err) {
      console.error("❌ Error al cargar datos:", err);
    }
  };

  const buscarProducto = (texto) => {
    setBusquedaProducto(texto);
    const producto = productos.find((p) =>
      (p.nombre || "").toLowerCase().includes(texto.toLowerCase())
    );
    setProductoSeleccionado(producto || null);
  };

  const agregarAlCarrito = () => {
    if (!productoSeleccionado || cantidad <= 0) return;

    const stockActual = Number(productoSeleccionado.stock || 0);
    const prodID = productoSeleccionado._id; 

    if (stockActual < cantidad) {
      setMensaje(`❌ Stock insuficiente. Disponible: ${stockActual}`);
      return;
    }

    const existente = carrito.find((p) => p.ProductID === prodID);

    if (existente) {
      if (existente.Cantidad + cantidad > stockActual) {
        setMensaje("❌ No puedes superar el stock disponible");
        return;
      }
      setCarrito(carrito.map((p) => 
        p.ProductID === prodID ? { ...p, Cantidad: p.Cantidad + cantidad } : p
      ));
    } else {
      setCarrito([...carrito, {
        ProductID: prodID, // ✅ Coincide con tu Backend: p.ProductID
        Nombre: productoSeleccionado.nombre,
        Cantidad: cantidad, // ✅ Coincide con tu Backend: p.Cantidad
        PrecioUnitario: Number(productoSeleccionado.precio)
      }]);
    }

    setProductoSeleccionado(null);
    setBusquedaProducto("");
    setCantidad(1);
    setMensaje("✅ Añadido al carrito");
    setTimeout(() => setMensaje(""), 1500);
  };

  const calcularSubtotal = () =>
    carrito.reduce((acc, p) => acc + p.Cantidad * p.PrecioUnitario, 0);

  const realizarVenta = async () => {
    if (!clienteNombre.trim() || !clienteApellido.trim() || carrito.length === 0) {
      setMensaje("⚠️ Completa los datos del cliente y el carrito.");
      return;
    }

    setLoading(true);
    setMensaje("⏳ Procesando transacción...");

    try {
      // 1. Verificar si el cliente ya existe por nombre y apellido
      let clienteExistente = clientes.find(
        (c) => (c.nombre || "").toLowerCase() === clienteNombre.toLowerCase() &&
               (c.apellido || "").toLowerCase() === clienteApellido.toLowerCase()
      );

      // 2. Construir el PAYLOAD exacto para tu controlador registrarVenta
      const payload = {
        ClienteID: clienteExistente?._id || null, // Si es null, el backend crea uno nuevo
        Nombre: clienteNombre,
        Apellido: clienteApellido,
        Telefono: clienteTelefono || "",
        productos: carrito.map((p) => ({
          ProductID: p.ProductID, // 👈 Importante: p.ProductID como en tu for loop
          Cantidad: p.Cantidad    // 👈 Importante: p.Cantidad como en tu for loop
        })),
        metodoPago: "efectivo"
      };

      // 3. Petición a la ruta que definiste en tu backend
      const res = await api.post("/ventas/registrar", payload);

      // 4. Mapear respuesta para el Ticket
      const ticketData = {
        _id: res.data.VentaID,
        NumeroSecuencia: res.data.NumeroTicket,
        Total: res.data.Total,
        Subtotal: calcularSubtotal(),
        IVA: calcularSubtotal() * 0.12, // Tu backend usa 12%
        Fecha: new Date(),
        NombreCliente: `${clienteNombre} ${clienteApellido}`,
        productos: carrito // Usamos los datos locales para el ticket
      };

      setTicket(ticketData);
      setMensaje("✅ Venta registrada correctamente.");
      setCarrito([]);
      setClienteNombre("");
      setClienteApellido("");
      setClienteTelefono("");
      
      // Actualizar stocks y clientes localmente
      cargarDatos();
      
    } catch (err) {
      console.error(err);
      const msgError = err.response?.data?.msg || "Error al procesar la transacción";
      setMensaje(`❌ Error: ${msgError}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container-fluid p-4 bg-light min-vh-100">
      <div className="d-flex align-items-center mb-4">
        <FaCashRegister className="fs-2 text-primary me-3" />
        <h2 className="fw-bold mb-0">Punto de Venta (Barrios)</h2>
      </div>

      <div className="row">
        <div className="col-lg-7">
          <div className="card shadow-sm border-0 p-4 mb-4 rounded-4">
            <h5 className="fw-bold mb-3"><FaSearch className="me-2 text-secondary" /> 1. Buscar Productos</h5>
            <input
              type="text"
              className="form-control mb-3 border-0 bg-light p-3"
              placeholder="Buscar por nombre..."
              value={busquedaProducto}
              onChange={(e) => buscarProducto(e.target.value)}
            />

            {productoSeleccionado && (
              <div className="card bg-primary text-white border-0 shadow-sm p-3 mb-4">
                <div className="d-flex justify-content-between align-items-center">
                  <div>
                    <h6 className="mb-0 fw-bold">{productoSeleccionado.nombre}</h6>
                    <small>Stock: {productoSeleccionado.stock} | Precio: ${productoSeleccionado.precio}</small>
                  </div>
                  <div className="d-flex gap-2">
                    <input type="number" className="form-control form-control-sm text-center" style={{ width: "60px" }} value={cantidad} onChange={(e) => setCantidad(Number(e.target.value))} min="1" />
                    <button className="btn btn-light btn-sm fw-bold" onClick={agregarAlCarrito}><FaCartPlus /></button>
                  </div>
                </div>
              </div>
            )}

            <h5 className="fw-bold mb-3 mt-2"><FaUser className="me-2 text-secondary" /> 2. Datos del Cliente</h5>
            <div className="row g-2">
              <div className="col-md-6"><input className="form-control" placeholder="Nombre" value={clienteNombre} onChange={(e) => setClienteNombre(e.target.value)} /></div>
              <div className="col-md-6"><input className="form-control" placeholder="Apellido" value={clienteApellido} onChange={(e) => setClienteApellido(e.target.value)} /></div>
              <div className="col-12"><input className="form-control" placeholder="Teléfono" value={clienteTelefono} onChange={(e) => setClienteTelefono(e.target.value)} /></div>
            </div>

            {mensaje && <div className={`alert mt-3 border-0 shadow-sm ${mensaje.includes('✅') ? 'alert-success' : 'alert-danger'}`}>{mensaje}</div>}
          </div>
        </div>

        <div className="col-lg-5">
          <div className="card shadow-sm border-0 p-4 bg-white h-100 rounded-4">
            <h5 className="fw-bold text-dark mb-4 border-bottom pb-2">🛒 Detalle de Venta</h5>
            <div className="table-responsive" style={{ minHeight: "250px" }}>
              <table className="table table-sm align-middle">
                <thead>
                  <tr className="text-muted small">
                    <th>Producto</th>
                    <th className="text-center">Cant.</th>
                    <th className="text-end">Subtotal</th>
                    <th></th>
                  </tr>
                </thead>
                <tbody>
                  {carrito.map((p) => (
                    <tr key={p.ProductID}>
                      <td className="small fw-bold">{p.Nombre}</td>
                      <td className="text-center">{p.Cantidad}</td>
                      <td className="text-end">${(p.Cantidad * p.PrecioUnitario).toFixed(2)}</td>
                      <td className="text-end text-danger" style={{cursor:'pointer'}} onClick={() => setCarrito(carrito.filter(i => i.ProductID !== p.ProductID))}><FaTrash /></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <div className="mt-auto pt-3 border-top">
              <div className="d-flex justify-content-between fs-3 fw-bold text-success">
                <span>TOTAL:</span>
                <span>${(calcularSubtotal() * 1.12).toFixed(2)}</span>
              </div>
              <button className="btn btn-success btn-lg w-100 mt-4 shadow-sm fw-bold py-3 rounded-pill" onClick={realizarVenta} disabled={carrito.length === 0 || loading}>
                {loading ? "PROCESANDO..." : "💰 FINALIZAR VENTA"}
              </button>
            </div>
          </div>
        </div>
      </div>

      {ticket && (
        <div className="modal show d-block" style={{ backgroundColor: "rgba(0,0,0,0.6)" }}>
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content border-0 bg-transparent">
               <TicketVenta ticket={ticket} setTicket={setTicket} />
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
